    int64_t axis = dimAttr;
    if (axis < 0) axis += rank;
    if (axis < 0 || axis >= rank) {
        return GRAPH_FAILED;
    }

    // Build output dims by removing the reduced axis
    std::vector<int64_t> outDims;
    outDims.reserve(static_cast<size_t>(rank - 1));
